import{_ as e,c as t,o,a1 as d}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Configuração Avançada: Explicação Detalhada de Funcionalidades Avançadas | Antigravity-Manager","description":"Aprenda métodos de configuração avançada do Antigravity-Manager. Domine agendamento de conta, roteamento de modelo, governança de cota e monitoramento estatístico, entre outras funcionalidades avançadas.","frontmatter":{"title":"Configuração Avançada: Explicação Detalhada de Funcionalidades Avançadas | Antigravity-Manager","order":300,"sidebarTitle":"Elevar Sistema para Nível de Produção","subtitle":"Configuração Avançada: Explicação Detalhada de Funcionalidades Avançadas","description":"Aprenda métodos de configuração avançada do Antigravity-Manager. Domine agendamento de conta, roteamento de modelo, governança de cota e monitoramento estatístico, entre outras funcionalidades avançadas."},"headers":[],"relativePath":"pt/lbjlaq/Antigravity-Manager/advanced/index.md","filePath":"pt/lbjlaq/Antigravity-Manager/advanced/index.md"}'),n={name:"pt/lbjlaq/Antigravity-Manager/advanced/index.md"};function r(s,a,i,l,p,c){return o(),t("div",null,[...a[0]||(a[0]=[d(`<h1 id="configuracao-avancada" tabindex="-1">Configuração Avançada <a class="header-anchor" href="#configuracao-avancada" aria-label="Permalink to &quot;Configuração Avançada&quot;">​</a></h1><p>Este capítulo aprofunda funcionalidades avançadas do Antigravity Tools: gerenciamento de configuração, estratégia de segurança, agendamento de conta, roteamento de modelo, governança de cota, monitoramento e estatísticas, e planos de implantação de servidor. Após dominar estes conteúdos, você pode elevar Antigravity Tools de &quot;pode usar&quot; para &quot;bom uso, estável, operável&quot;.</p><h2 id="conteudo-do-capitulo" tabindex="-1">Conteúdo do Capítulo <a class="header-anchor" href="#conteudo-do-capitulo" aria-label="Permalink to &quot;Conteúdo do Capítulo&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Tutorial</th><th>Descrição</th></tr></thead><tbody><tr><td><a href="./config/">Configuração Completa</a></td><td>Campos completos de AppConfig/ProxyConfig, localização de persistência e semântica de atualização a quente</td></tr><tr><td><a href="./security/">Segurança e Privacidade</a></td><td><code>auth_mode</code>, <code>allow_lan_access</code> e design de linha de base de segurança</td></tr><tr><td><a href="./scheduling/">Agendamento de Alta Disponibilidade</a></td><td>Rotação, conta fixa, sessão aderente e mecanismo de retry em caso de falha</td></tr><tr><td><a href="./model-router/">Roteamento de Modelo</a></td><td>Mapeamento personalizado, prioridade de curinga e estratégias predefinidas</td></tr><tr><td><a href="./quota/">Governança de Cota</a></td><td>Combinação de Quota Protection + Smart Warmup</td></tr><tr><td><a href="./monitoring/">Proxy Monitor</a></td><td>Logs de solicitação, filtragem, restauração de detalhes e exportação</td></tr><tr><td><a href="./token-stats/">Token Stats</a></td><td>Métrica de perspectiva de custo e interpretação de gráficos</td></tr><tr><td><a href="./context-compression/">Estabilidade de Sessão Longa</a></td><td>Compressão de contexto, cache de assinatura e compressão de resultados de ferramentas</td></tr><tr><td><a href="./system/">Capacidade do Sistema</a></td><td>Multilínguagem/tema/atualização/início automático/HTTP API Server</td></tr><tr><td><a href="./deployment/">Implantação de Servidor</a></td><td>Docker noVNC vs Headless Xvfb seleção de tipo e operações</td></tr></tbody></table><h2 id="sugestao-de-caminho-de-aprendizado" tabindex="-1">Sugestão de Caminho de Aprendizado <a class="header-anchor" href="#sugestao-de-caminho-de-aprendizado" aria-label="Permalink to &quot;Sugestão de Caminho de Aprendizado&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Ordem recomendada</p><p>Este capítulo tem muito conteúdo, recomenda aprender em módulos em lote:</p></div><p><strong>Fase 1: Configuração e Segurança (aprender primeiro)</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Configuração Completa → Segurança e Privacidade</span></span>
<span class="line"><span>config             security</span></span></code></pre></div><p>Primeiro entenda sistema de configuração (quais precisam de reinício, quais atualização a quente), depois aprenda configurações de segurança (especialmente ao expor para LAN/rede pública).</p><p><strong>Fase 2: Agendamento e Roteamento (recomendado)</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Agendamento de Alta Disponibilidade → Roteamento de Modelo</span></span>
<span class="line"><span>scheduling              model-router</span></span></code></pre></div><p>Use número mínimo de contas para obter máxima estabilidade, depois use roteamento de modelo para blindar mudanças upstream.</p><p><strong>Fase 3: Cota e Monitoramento (conforme necessário)</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Governança de Cota → Proxy Monitor → Token Stats</span></span>
<span class="line"><span>quota                 monitoring      token-stats</span></span></code></pre></div><p>Evite cota esgotar imperceptivelmente, transformar chamada de caixa preta em sistema observável, quantificar custo otimizar.</p><p><strong>Fase 4: Estabilidade e Implantação (avançado)</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Estabilidade de Sessão Longa → Capacidade do Sistema → Implantação de Servidor</span></span>
<span class="line"><span>context-compression          system            deployment</span></span></code></pre></div><p>Resolva problemas ocultos de sessão longa, deixar cliente mais parecido com produto, finalmente aprenda implantação de servidor.</p><p><strong>Seleção Rápida</strong>:</p><table tabindex="0"><thead><tr><th>Seu cenário</th><th>Recomendado ver primeiro</th></tr></thead><tbody><tr><td>Rotação de múltiplas contas instável</td><td><a href="./scheduling/">Agendamento de Alta Disponibilidade</a></td></tr><tr><td>Quer fixar certo nome de modelo</td><td><a href="./model-router/">Roteamento de Modelo</a></td></tr><tr><td>Cota sempre esgota</td><td><a href="./quota/">Governança de Cota</a></td></tr><tr><td>Quer ver logs de solicitação</td><td><a href="./monitoring/">Proxy Monitor</a></td></tr><tr><td>Quer estatísticas de consumo de token</td><td><a href="./token-stats/">Token Stats</a></td></tr><tr><td>Diálogos longos frequentemente erram</td><td><a href="./context-compression/">Estabilidade de Sessão Longa</a></td></tr><tr><td>Quer expor para LAN</td><td><a href="./security/">Segurança e Privacidade</a></td></tr><tr><td>Quer implantar em servidor</td><td><a href="./deployment/">Implantação de Servidor</a></td></tr></tbody></table><h2 id="pre-requisitos" tabindex="-1">Pré-requisitos <a class="header-anchor" href="#pre-requisitos" aria-label="Permalink to &quot;Pré-requisitos&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Confirme antes de começar</p><ul><li>Completou <a href="./../start/">Início Rápido</a> capítulos (pelo menos completou instalação, adicionar conta, iniciar proxy reverso)</li><li>Completou pelo menos um protocolo de integração em <a href="./../platforms/">Plataformas e Integrações</a> (como OpenAI ou Anthropic)</li><li>Proxy reverso local consegue responder solicitações normalmente</li></ul></div><h2 id="proximos-passos" tabindex="-1">Próximos Passos <a class="header-anchor" href="#proximos-passos" aria-label="Permalink to &quot;Próximos Passos&quot;">​</a></h2><p>Após completar este capítulo, você pode continuar aprendendo:</p><ul><li><a href="./../faq/">Perguntas Frequentes</a>: guia de solução de problemas ao encontrar erros 401/404/429/interrupção de fluxo</li><li><a href="./../appendix/">Apêndice</a>: tabela rápida de endpoints, modelo de dados, fronteiras de capacidades z.ai, etc. referências</li></ul>`,25)])])}const g=e(n,[["render",r]]);export{u as __pageData,g as default};
